#include <bits/stdc++.h>
using namespace std;
int main(){int k;scanf("%d",&k);stack<long long>st;long long sum=0;while(k--){long long x;scanf("%lld",&x);if(x==0){sum-=st.top();st.pop();}else{st.push(x);sum+=x;}}printf("%lld\n",sum);}
